function compile (spec: string): {
  regex: string
  props: string[]
} {
  const parts: string[] = []
  const props: string[] = []
  let min = 0
  let max = 0
  let any = false
  let opt = true
  function flatten (final: boolean = false): void {
    if (max > 0 || any) {
      if (final && opt && min < 1) {
        min = 1
      } else if (min > 0) {
        opt = false
      }
