        max++
        break
      case '++':
        max++
        break
      case '*':
        min++
        any = true
        break
      case '**':
        any = true
        break
      default:
        flatten()
        opt = false
        if (part.match(/:.+/) !== null) {
          props.push(part.slice(1))
          parts.push('/([^/]+)')
